current_version":1,"markup_multiplier":7,"contribution_margin":1800,"performance_bonus_percent":0,"markup_multiplier_override":null},{"id":"523dfc26-fefe-4902-8e94-59260cb03da8","name":"Perfume Packshot","tags":[],"status":"published","user_id":"d873b284-c192-45a2-af86-c2314e7c7ce8","api_cost":600,"category":"Photography","keywords":[],"settings":{"graph":{"edges":[{"id":"xy-edge__fc55dae9-912e-4f17-b3cc-2da3eb87cf5cdefault-e053d36d-e87d-42c9-a6f8-a5222c7255f8ref_image","source":"fc55dae9-912e-4f17-b3cc-2da3eb87cf5c","target":"e053d36d-e87d-42c9-a6f8-a5222c7255f8","sourceHandle":"default","targetHandle":"ref_image"},{"id":"xy-edge__e053d36d-e87d-42c9-a6f8-a5222c7255f8image-99256e10-094f-4256-94f5-5135ba664965default","source":"e053d36d-e87d-42c9-a6f8-a5222c7255f8","target":"99256e10-094f-4256-94f5-5135ba664965","sourceHandle":"image","targetHandle":"default"},{"id":"xy-edge__fc55dae9-912e-4f17-b3cc-2da3eb87cf5cdefault-8b266275-a3dc-415e-b510-cf9537a3e9ffref_image","source":"fc55dae9-912e-4f17-b3cc-2da3eb87cf5c","target":"8b266275-a3dc-415e-b510-cf9537a3e9ff","sourceHandle":"default","targetHandle":"ref_image"},{"id":"xy-edge__8b266275-a3dc-415e-b510-cf9537a3e9ffimage-7c0db9c9-39c7-44d8-9eaf-fd834d7187a4default","source":"8b266275-a3dc-415e-b510-cf9537a3e9ff","target":"7c0db9c9-39c7-44d8-9eaf-fd834d7187a4","sourceHandle":"image","targetHandle":"default"}],"nodes":[{"id":"fc55dae9-912e-4f17-b3cc-2da3eb87cf5c","data":{"label":"Image Upload","accept":"image/*","nodeName":"Image Upload","required":true,"fieldType":"image","fieldLabel":"Upload your image"},"type":"inputNode","position":{"x":-300,"y":360}},{"id":"e053d36d-e87d-42c9-a6f8-a5222c7255f8","data":{"label":"Banana Pro (Image Gen)","params":{"model":"nano-banana-pro","prompt":"Create a high-end commercial marketing campaign visual centered on the uploaded product.\n\nMaintain perfect visual consistency and brand integrity at all times.\n\n--------------------------------------\n\nSTEP 1 — PRODUCT ANALYSIS (MANDATORY)\n\nAnalyze the product visually before designing:\n\n• Product category and real-world usage\n\n• Functional interaction context\n\n• Dominant and accent color palette\n\n• Material (metal, glass, liquid, fabric, paper, matte, gloss, etc.)\n\n• Brand personality (luxury, bold, artistic, minimal, energetic, organic, tech-forward, etc.)\n\nAll creative and artistic decisions must be derived strictly from this analysis.\n\nDo NOT introduce unrelated objects.\n\nAll props must logically support product function or identity.\n\n--------------------------------------\n\nCORE ART DIRECTION\n\nDevelop a bold, artistic, visually striking luxury concept inspired by the product’s purpose and color palette.\n\nElevate the scene with:\n\n• Dynamic color gradients derived from product tones\n\n• Layered lighting depth\n\n• Controlled artistic shadow play\n\n• Subtle abstract forms inspired by product function (liquid flow, ink stroke, foam curve, fabric tension, light streak, etc.)\n\nArtistic but intentional.\n\nExpressive yet refined.\n\nNo randomness.\n\n--------------------------------------\n\nHERO SHOT\n\nCreate a bold, iconic still life hero composition.\n\nProduct centered and dominant.\n\nUse sculptural lighting to add drama.\n\nIntroduce subtle color contrast or complementary accent glow derived from product palette.\n\nStrong visual presence with artistic negative space.\n\n--------------------------------------\n\nMACRO DETAIL\n\nExtreme macro detail highlighting:\n\n• Surface micro-texture\n\n• Material depth\n\n• Color transitions\n\n• Craft precision\n\nHyper-realistic, ultra sharp.\n\nRich tonal contrast.\n\nCinematic micro lighting.\n\n--------------------------------------\n\nSENSORY CLOSE-UP\n\nCreate a tactile close-up emphasizing realism:\n\n• Texture interaction\n\n• Relevant functional elements (ink, foam, liquid, powder, reflection, etc.)\n\n• Motion suggestion (frozen splash, light streak, fabric flow) only if logically connected to product\n\nNo exaggerated fantasy.\n\nKeep physical believability.\n\n--------------------------------------\n\nCOLOR-DRIVEN CONCEPT\n\nDesign a visually expressive color environment inspired by the product’s palette.\n\nIncorporate:\n\n• Bold yet harmonious gradients\n\n• Controlled color blocking\n\n• Subtle color light wrapping\n\n• Soft atmospheric glow\n\nMaintain luxury sophistication.\n\nAvoid neon overload unless brand identity demands it.\n\n--------------------------------------\n\nVISUAL RULES\n\nThe product must remain 100% accurate in:\n\n• Shape\n\n• Proportion\n\n• Label\n\n• Font\n\n• Logo\n\n• Color\n\n• Brand identity\n\nNo distortion.\n\nNo warping.\n\nNo redesign.\n\nNo geometry alteration.\n\nClear separation between product and background.\n\nRealistic grounding shadow.\n\n--------------------------------------\n\nLIGHTING & STYLE\n\nSoft but sculptural studio lighting.\n\nControlled highlights.\n\nDeep yet natural shadows.\n\nHigh dynamic range.\n\nUltra-sharp focus.\n\nLuxury editorial-grade post-processing.\n\nPhotorealistic — not artificial CGI.\n\n--------------------------------------\n\nOVERALL FEEL\n\nArtistic.\n\nBold.\n\nSophisticated.\n\nVisually rich.\n\nColor-driven.\n\nCinematic.\n\nAspirational.\n\nHigh-end sensory marketing aesthetic.\n\nDesigned for:\n\nPremium brand campaigns.\n\nSocial media hero visuals.\n\nDigital billboards.\n\nLuxury e-commerce platforms.\n\nAspect ratio 3:4.\n\nUltra high resolution.\n\nCommercial production quality.","edit_instruction":""},"exposed":{}},"type":"bananaProNode","position":{"x":30,"y":0}},{"id":"99256e10-094f-4256-94f5-5135ba664965","data":{"label":"Output","outputType":"video"},"type":"outputNode","position":{"x":405,"y":270}},{"id":"8b266275-a3dc-415e-b510-cf9537a3e9ff","data":{"label":"Banana Pro (Image Gen)","params":{"model":"nano-banana-pro","prompt":"Create a high-end luxury perfume campaign visual, close-up of a sensual woman’s neck and collarbone area as she sprays perfume onto her skin. Aspect ratio 3:4, ultra high resolution, photorealistic, commercial production quality.\n\nFrame the composition from just below the lips down to the collarbone. Her head is slightly tilted back, exposing the elegant curve of the neck. Expression subtle and confident, lips softly parted but refined — sensual yet sophisticated, not explicit.\n\nThe perfume bottle must remain 100% accurate in shape, proportion, label, logo, font, color, and material finish. No distortion, no redesign, no geometry alteration.\n\nCapture the precise moment of atomized mist dispersing from the nozzle toward the neck. The mist should appear ultra-fine, softly illuminated by controlled backlight, with realistic diffusion and natural falloff. No exaggerated fantasy effects.\n\nEmphasize tactile realism:\n• Natural skin texture with visible pores (not plastic or overly retouched)\n• Soft highlight along the collarbone\n• Subtle sheen where the mist lands\n• Gentle shadow shaping under the jawline\n\nLighting should be soft yet sculptural studio lighting:\n• Warm key light shaping the neck contour\n• Subtle rim light separating skin from background\n• Delicate backlight enhancing mist particles\n\nBackground must be a refined gradient inspired by the perfume’s color palette. Harmonized tones, controlled color transitions, soft atmospheric glow. No random props or decorative elements.\n\nMaintain clear separation between subject and background, realistic grounding, and high dynamic range. Ultra-sharp focus on the spray interaction point.\n\nOverall feel: sensual, elegant, cinematic, modern, aspirational luxury. Suitable for premium perfume campaigns, high-end social media visuals, digital billboards, and luxury e-commerce platforms.","edit_instruction":""},"exposed":{}},"type":"bananaProNode","position":{"x":30,"y":555}},{"id":"7c0db9c9-39c7-44d8-9eaf-fd834d7187a4","data":{"label":"Output","outputType":"video"},"type":"outputNode","position":{"x":405,"y":570}}]},"example_inputs":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-example-input-523dfc26-fefe-4902-8e94-59260cb03da8-1775456667986-0.jpeg?t=1775456668589"],"preview_images":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-523dfc26-fefe-4902-8e94-59260cb03da8-1775131793508-0.png?t=1775131795750"],"setup_instructions":"อัปโหลดภาพขวดน้ำหอมหรือสินค้ากลุ่มเครื่องหอมของคุณ แล้วกดสร้างภาพได้ทันที"},"base_cost":600,"embedding":"[0.002227334,-0.013630458,-0.015194049,-0.11446762,-0.030240124,0.005399937,-0.0075875856,0.021297663,-0.004001815,-0.015089684,-0.013174594,-0.014055038,-0.0015049501,-0.025459677,0.13748103,0.0089869145,-0.015713286,0.027078701,0.022110075,-0.010561153,-0.016099984,0.018041573,0.008443795,7.059945e-05,0.016286258,-0.01651871,0.011730191,-0.011691745,0.0142010255,0.030645393,0.0061936076,0.0042318464,0.024252776,0.015992159,0.015783533,0.011562409,0.006599384,-0.02031711,0.011956788,0.015766991,-0.039191127,0.015914096,0.017124703,0.022965543,0.024833316,0.002554415,0.022209628,-0.028763255,0.026827546,0.008945124,0.0018493898,0.00029314152,-0.024297776,-0.1503312,-0.008281597,0.005360791,-0.008698242,-0.012955136,-0.018497061,-0.02321211,-0.0011929643,0.042216163,0.0004614797,-0.025932943,-0.021801554,-0.037123784,0.002762026,-0.009967247,-0.009256906,0.018246273,-0.0051418324,0.031173477,-0.014572838,0.014404362,0.031311113,0.0029492588,0.002933175,0.015888901,-0.020548582,0.025093105,-0.01289191,0.0054626325,-0.034507733,-0.008069658,0.012375937,-0.022472538,-0.0034206493,0.006575323,0.013537047,0.009284975,0.0058402717,-0.0052040736,0.014136314,0.023738842,-0.024177628,-0.00062244426,0.018950112,1.459106e-05,-0.02287763,-0.02375886,0.017843831,-0.02544827,0.018481204,-0.0139562525,0.00809672,0.0136165805,-0.031197112,-0.017936893,-0.016939696,-0.008151827,0.0054656803,-0.014275177,0.009200196,0.012575974,0.0068663224,-0.12