-4c84-9ce1-35a6b0bdeb20default-ab06cb42-83c7-460f-aa57-35c8ef3ad0a5ref_image","source":"73822175-1b6f-4c84-9ce1-35a6b0bdeb20","target":"ab06cb42-83c7-460f-aa57-35c8ef3ad0a5","sourceHandle":"default","targetHandle":"ref_image"},{"id":"xy-edge__ab06cb42-83c7-460f-aa57-35c8ef3ad0a5image-3fd70af9-33cc-47dd-a4e3-887611a11d7cdefault","source":"ab06cb42-83c7-460f-aa57-35c8ef3ad0a5","target":"3fd70af9-33cc-47dd-a4e3-887611a11d7c","sourceHandle":"image","targetHandle":"default"}],"nodes":[{"id":"45110c4f-9906-428a-b789-bc764a8d4e04","data":{"label":"Image Upload","accept":"image/*","nodeName":"Upload your Old Packaging","required":true,"fieldType":"image","fieldLabel":"Upload your Old Packaging"},"type":"inputNode","position":{"x":-75,"y":345}},{"id":"73822175-1b6f-4c84-9ce1-35a6b0bdeb20","data":{"label":"Image Upload","accept":"image/*","nodeName":"Upload your Logo","required":true,"fieldType":"image","fieldLabel":"Upload your Logo"},"type":"inputNode","position":{"x":-75,"y":645}},{"id":"ab06cb42-83c7-460f-aa57-35c8ef3ad0a5","data":{"label":"Banana Pro (Image Gen)","params":{"prompt":"Create a premium, photorealistic product packaging shot of a Plastic beverage bottle standing upright in a bright minimalist studio setting. The packaging has a sleek modern silhouette with a refined matte or semi-matte surface texture. The overall aesthetic is high-end, commercially realistic, and suitable for a premium FMCG brand.\n\nUse the original packaging color of the product as the main color direction. Preserve the core brand color identity from the original product packaging, and build the redesigned label composition around that existing color palette. The AI may enhance the tones, contrast, gradients, or material richness, but must stay clearly within the same color family as the original packaging. The output must also stay consistent with the original product’s flavor or scent identity suggested by the packaging, so the final result visually matches the same taste profile rather than feeling like a different variant. Do not replace the product with an unrelated new color scheme.\n\nProminently display the @@[Upload your Logo](73822175-1b6f-4c84-9ce1-35a6b0bdeb20)  at the top of the front label. Center the main product name in elegant, readable typography: ##[HEAD LINE](7d346ddc-75ea-4c01-ace6-4a6d520969e8)  . Below it, place the secondary text: ##[SECONDARY TEXT](0158c2b7-abbe-4b40-ad44-400235586063) .\n\nDesign a complete front-of-pack label composition with a strong visual hierarchy. Do not simply place an existing cropped product image onto the packaging. If the ingredient image, product image, or key visual is incomplete, cropped, partially missing, or not wide enough, intelligently extend, reconstruct, and redesign the missing areas. The AI should generate additional matching visual elements so the final composition feels complete, intentional, and professionally designed.\n\nThe packaging artwork should include:\n\n- one clear hero visual of the main ingredient or product\n\n- supporting visual elements that enhance the hero image\n\n- natural continuation of shapes, textures, and details beyond the original image boundaries\n\n- balanced spacing and negative space for typography\n\n- a composition optimized specifically for the packaging format\n\n- no awkward cutoffs, no empty gaps, no obvious pasted collage look\n\nAny newly generated visual elements must harmonize with the original packaging color palette and brand mood. Decorative elements, ingredient visuals, textures, splashes, leaves, powders, or abstract graphics should feel like part of the same packaging system, not separate pasted assets.\n\nMake the visual composition look like a real premium packaging design system, not just a photo sticker. The artwork should feel cohesive, brand-consistent, and print-ready, with subtle depth, elegant framing, and refined layering. Lighting should be soft and diffused, emphasizing material realism and premium finish. The final result should look like a luxury commercial product photography campaign with believable packaging print detail.","model_name":"nano-banana-2","aspect_ratio":"3:4"},"exposed":{}},"type":"bananaProNode","position":{"x":300,"y":345}},{"id":"3fd70af9-33cc-47dd-a4e3-887611a11d7c","data":{"label":"Output","outputType":"video"},"type":"outputNode","position":{"x":675,"y":345}},{"id":"7d346ddc-75ea-4c01-ace6-4a6d520969e8","data":{"label":"Text Input","nodeName":"HEAD LINE","textValue":"","fieldLabel":"YOUR HEAD LINE PRODUCT","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":270,"y":855}},{"id":"0158c2b7-abbe-4b40-ad44-400235586063","data":{"label":"Text Input","nodeName":"SECONDARY TEXT","textValue":"","fieldLabel":"YOUR SECONDARY TEXT","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":585,"y":855}}]},"example_inputs":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-example-input-309ecb2e-e058-42a8-8701-9fcf83490435-1775378443962-0.png?t=1775378445674"],"preview_images":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-309ecb2e-e058-42a8-8701-9fcf83490435-1775112332724-0.PNG?t=1775112334608","https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-309ecb2e-e058-42a8-8701-9fcf83490435-1775112334609-1.PNG?t=1775112335181","https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-309ecb2e-e058-42a8-8701-9fcf83490435-1775112335181-2.PNG?t=1775112335790","https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-309ecb2e-e058-42a8-8701-9fcf83490435-1775112587372-0.PNG?t=1775112589885","https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/pu