gtoiozqztoszvkuc.supabase.co/storage/v1/object/sign/ai-media/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/8c30c134-4722-4bb8-b345-9b500a0d3b58.png?token=eyJraWQiOiJzdG9yYWdlLXVybC1zaWduaW5nLWtleV9jM2VkYzBhMy1jMDIyLTQyOTgtODIxMS1mMTc5YTA1ZDUxN2IiLCJhbGciOiJIUzI1NiJ9.eyJ1cmwiOiJhaS1tZWRpYS9mYjRkZTdlMi05ZjZlLTQ1OWItYmIxYi00NjRmNmFlMTRiZWEvOGMzMGMxMzQtNDcyMi00YmI4LWIzNDUtOWI1MDBhMGQzYjU4LnBuZyIsImlhdCI6MTc3NTQ1MDU2NywiZXhwIjoxNzc1NTM2OTY3fQ.IaOv1PX2ynWABcxoJB_ku89y0x-wjFLcXTX6v89ROw8","storagePath":"fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/8c30c134-4722-4bb8-b345-9b500a0d3b58.png","creatorAsset":true},"type":"inputNode","position":{"x":-225,"y":525}},{"id":"1b78f167-1182-498a-9bfa-1ff4fdab339e","data":{"label":"Banana Pro (Image Gen)","params":{"prompt":"High-end editorial luxury beauty close-up, tight narrow-angle magazine crop (face and shoulders), 4K ultra-sharp. Use the same female model as@[นางแบบ](8f673af1-0d39-424b-b3cf-a90851e6abfd)  (match facial structure, skin tone, proportions, and hair). Pose locked to@[Creator Image](6c2ceee7-5185-4b60-bd14-0c75302187ce)  : left arm raised perpendicular covering half of the face, right hand touching the left hand near the forehead; elegant long fingers, clean finger edges, anatomically correct hands. Nails painted to match the jewelry metal tone.\r\n\r\n\r\n\r\nMakeup: high-fashion glam—sharp defined brows, winged eyeliner, crisp lashes, semi-matte skin with subtle highlight (visible pores, not plastic), deep velvet dark-red lips. Expression confident and intense; focus on the eyes and jewelry with very shallow depth of field.\r\n\r\n\r\n\r\nJewelry must be EXACTLY the same set as @[เซ็ตเครื่องประดับ](6b592fac-801e-430f-ac02-9bd2f3b04234)  only: silver/white-gold diamond  earrings,  diamond pendant necklace,  diamond ring, and matching bracelet; real gemstone sparkle, crisp prongs, sharp facets, clean reflections, luxury product-level detail. Outfit: dark-toned editorial fashion (satin or soft leather with beautiful sheen), off-shoulder or slightly deep V neckline to showcase necklace; clothing color harmonized with the jewelry but darker for contrast. Lighting: dramatic studio beauty lighting with soft deep shadows, cinematic contrast, controlled specular highlights on metal and gems. Background: plain dark studio backdrop, slightly blurred, no texture, no distractions. Vogue-like cinematic beauty close-up, premium fashion magazine aesthetic.\r\n\r\n\r\n\r\nNegative prompt: full body, wide angle, street/outdoor scene, text, logo, watermark, wrong jewelry set, jewelry color not silver/white-gold with clear diamonds, extra/missing fingers, deformed hands, distorted face, cross-eyed, visible teeth, overly plastic skin, blur, heavy noise, harsh on-camera flash, excessive glitter/sparkle artifacts.","model_name":"nano-banana-pro","aspect_ratio":"3:4"},"exposed":{}},"type":"bananaProNode","position":{"x":120,"y":0}},{"id":"6b592fac-801e-430f-ac02-9bd2f3b04234","data":{"label":"Image Upload","accept":"image/*","nodeName":"เซ็ตเครื่องประดับ","required":true,"fieldType":"image","fieldLabel":"เซ็ตเครื่องประดับ"},"type":"inputNode","position":{"x":-225,"y":-135}},{"id":"eb2a7ea7-19dc-4357-ad40-86bd9a07a865","data":{"label":"Output","outputType":"video"},"type":"outputNode","position":{"x":480,"y":90}}]},"example_inputs":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-example-input-e8289601-1c0d-4318-b128-1521c87f9e6f-1775452691708-0.png?t=1775452692757","https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-example-input-e8289601-1c0d-4318-b128-1521c87f9e6f-1775460991554-0.jpg?t=1775460992630"],"preview_images":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-e8289601-1c0d-4318-b128-1521c87f9e6f-1775452651700-0.jpg?t=1775452653384","https://mlbzgtoiozqztoszvkuc.supabase.