get":"7b6d3b87-94c0-410a-92bc-b223a5c02d58","sourceHandle":"default","targetHandle":"ref_image"}],"nodes":[{"id":"7508c0c5-91cd-4ad4-b71b-a7c3b4317c9e","data":{"label":"Image Upload","accept":"image/*","config":{"example_image_urls":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/flow-assets/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/9ee8e581-e50a-4a6d-a62f-a9c837cf7b5f.jpg"]},"nodeName":"แก้วเครื่องดื่ม","required":true,"fieldType":"image","fieldLabel":"แก้วเครื่องดื่ม"},"type":"inputNode","position":{"x":-45,"y":165}},{"id":"7b6d3b87-94c0-410a-92bc-b223a5c02d58","data":{"label":"Banana Pro (Image Gen)","params":{"prompt":"สร้างแก้วกาแฟ อ้างอิงจากตัวอย่าง @@[แก้วเครื่องดื่ม](7508c0c5-91cd-4ad4-b71b-a7c3b4317c9e)  \nมีมือมนุษย์ @@[มือ](ac454e1e-a637-41df-9e72-08c5e25ac0a8) ที่ดูสมจริงก้าวเข้ามาจากด้านล่างขวาของเฟรมและถือแก้ว@@[แก้วเครื่องดื่ม](7508c0c5-91cd-4ad4-b71b-a7c3b4317c9e)  มีหยดน้ำเกาะตามธรรมชาติ และพื้นผิวพลาสติกมันวาวเล็กน้อย \n\nบรรยากาศสงบ สบาย ทันสมัย ​​และมีความเป็นศิลปะเล็กน้อย เหมือนช่วงเวลาบ่ายในร้านกาแฟที่ถ่ายด้วยแสงธรรมชาติ อารมณ์โดยรวมให้ความรู้สึกเงียบ อบอุ่น เหมือนภาพถ่ายนิตยสาร และมีความประณีตทางสุนทรียภาพ พร้อมด้วยแสงแดดและเงาที่เล่นกันอย่างชัดเจน\n\nพื้นหลังเป็นผนังที่มีพื้นผิวแบบด้านในสี (##[สีพื้นหลัง](995311f3-57dc-4929-9cbd-8245b9e328d1) ) ที่มีพื้นผิวละเอียดคล้ายปูนปลาสเตอร์ เงาจากกรอบหน้าต่างขนาดใหญ่ทอดตัวลงบนผนังในแนวทแยง สร้างรูปทรงเรขาคณิตที่โดดเด่นและองค์ประกอบแบบภาพยนตร์ แสงแดดในช่วงบ่ายเป็นแสงธรรมชาติที่แรง ทำให้เกิดเงาที่คมชัดแต่ขอบเบลอเล็กน้อย ทิศทางของแสงมาจากด้านบนซ้าย ทำให้เกิดแสงสะท้อนสว่างบนผนัง แก้ว และมือ ในขณะที่ยังคงความคมชัดสูงในบริเวณเงา\n\nองค์ประกอบภาพควรดูสมดุลและตั้งใจ:\n\nเครื่องดื่มวางอยู่บริเวณกลางล่างของเฟรม\n\nมือมองเห็นได้ตั้งแต่ข้อมือถึงนิ้ว จับแก้วอย่างเป็นธรรมชาติ\n\nมีพื้นที่ว่างเพียงพอรอบๆ ด้านบนและด้านข้าง\n\nพื้นหลังและเงาเป็นส่วนสำคัญขององค์ประกอบภาพ\n\nตัวแบบยังคงเป็นจุดโฟกัสหลัก ในขณะที่รูปแบบของเงาสร้างความลึกและอารมณ์\n\nสไตล์การถ่ายภาพ: ภาพถ่ายเครื่องดื่มเชิงพาณิชย์ที่สมจริง ภาพถ่ายร้านกาแฟระดับพรีเมียม แสงแดดธรรมชาติ ความคมชัดของเงาแบบภาพยนตร์ แสงสะท้อนอบอุ่นนุ่มนวล องค์ประกอบภาพสะอาดตา พื้นผิวของผิวหนังที่สมจริง วัสดุของแก้วที่สมจริง รายละเอียดสูง ความลึกที่ละเอียดอ่อน ภาพถ่ายผลิตภัณฑ์แบบไลฟ์สไตล์ ดูสง่างามและเรียบง่าย\n\nรักษาภาพให้สมจริง สวยงาม และพรีเมียม ด้วยสัดส่วนที่เป็นธรรมชาติและแสงที่ดูน่าเชื่อถือ ไม่ควรมีอุปกรณ์ประกอบฉากเพิ่มเติม เว้นแต่จะจำเป็นและเกี่ยวข้อง ไม่มีโต๊ะ ไม่มีสิ่งของรกเกะกะ ไม่มีวัตถุอื่นใดที่ดึงดูดความสนใจไปจากเครื่องดื่มและมือ ไม่มีข้อความ ไม่มีตัวอักษร ไม่มีโลโก้ ไม่มีลายน้ำ ไม่มีตราสินค้าใดๆ ในภาพ\n\nคำเตือนเชิงลบ:\n\nข้อความ ตัวอักษร คำ โลโก้ ชื่อแบรนด์ ลายน้ำ ฉลาก โปสเตอร์ มือเพิ่มเติม นิ้วผิดรูป กายวิภาคที่ไม่ถูกต้อง วัตถุลอยได้ พื้นหลังรก ฉากตกแต่งมากเกินไป แก้วหลายใบ เงาที่ไม่สมจริง คุณภาพต่ำ ภาพเบลอ การ์ตูน ภาพประกอบ ภาพที่ดูเหมือน CGI สีจัดเกินไป รูปทรงแก้วบิดเบี้ยว\n\n","model_name":"nano-banana-2","aspect_ratio":"Auto"},"exposed":{"aspect_ratio":true}},"type":"bananaProNode","position":{"x":390,"y":225}},{"id":"79aab09c-cf57-47b5-9fa2-4b1570194383","data":{"label":"Output","outputType":"video"},"type":"outputNode","position":{"x":795,"y":270}},{"id":"995311f3-57dc-4929-9cbd-8245b9e328d1","data":{"label":"Text Input","nodeName":"สีพื้นหลัง","textValue":"","fieldLabel":"สีพื้นหลัง","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":-45,"y":630}},{"id":"ac454e1e-a637-41df-9e72-08c5e25ac0a8","data":{"label":"Image Upload","accept":"image/*","config":{"example_image_urls":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/flow-assets/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/c1e80b34-ddf9-4a24-a367-85d82e97381c.jpg"]},"nodeName":"มือ","required":true,"fieldType":"image","fieldLabel":"มือ"},"type":"inputNode","position":{"x":-45,"y":885}}]},"example_inputs":[],"preview_images":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-d942bf26-7286-4d9f-b585-f9937ee5bd30-1775730312939-0.jpg?t=177