h as the hero.\r\n\r\nDo not add text, logos, watermarks, collage layout, hands, or unrelated dishes. Preserve realism and seasonal campaign appeal.","model_name":"nano-banana-pro","aspect_ratio":"Auto"},"exposed":{"aspect_ratio":true}},"type":"bananaProNode","position":{"x":210,"y":150}},{"id":"939ed35c-1799-4bc5-b4ab-0d71e7e827cc","data":{"label":"Text Input","nodeName":"Menu Name","textValue":"","fieldLabel":"อาหารของคุณคือ","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":540,"y":270}},{"id":"2d14f653-5575-4420-b65f-92956ffb4c2e","data":{"label":"Text Input","nodeName":"Seasonal Theme","textValue":"","fieldLabel":"ธีมที่ต้องการ เช่น Summer / Christmas / New Year / Valentine / Songkran / Autumn / Spring / Mango","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":540,"y":480}},{"id":"148a9967-a2dd-4021-92aa-7169f2fe6542","data":{"label":"Text Input","nodeName":"Optional dish details","textValue":"","fieldLabel":"รายละเอียดเพิ่มเติม เช่น เมนูนี้เป็นแบบร้อนหรือเย็น , เป็นเมนูสไตล์โฮมมี่ อบอุ่น ดูเข้าถึงง่าย","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":255,"y":705}},{"id":"c487ef75-eceb-4c34-9a79-74303d817bd6","data":{"label":"Text Input","nodeName":"Seasonal mood","textValue":"","fieldLabel":"อารมณ์ของภาพที่ต้องการ เช่น fresh and bright / cozy and warm / festive and elegant / romantic / playful / premium","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":540,"y":705}},{"id":"0ed527a7-2361-4dc9-bea2-df36bd6f6cb6","data":{"label":"Text Input","nodeName":"Color direction","textValue":"","fieldLabel":"โทนสีของภาพ เช่น ชมพูพาสเทล , แดงและทอง , ฟ้าสงกรานต์ , เขียวมัทฉะ","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":825,"y":270}},{"id":"2dbcc173-7a46-474d-9c62-b1339505643e","data":{"label":"Text Input","nodeName":"Seasonal props intensity","textValue":"","fieldLabel":"องค์ประกอบฤดูกาล เช่น Subtle = Seasonal เบาๆ , Medium = Seasonal พอด