wers, hands, or distracting props.","model_name":"nano-banana-pro","aspect_ratio":"Auto"},"exposed":{"aspect_ratio":true}},"type":"bananaProNode","position":{"x":420,"y":180}},{"id":"16cf341c-52fa-4191-8436-0fd804dd5506","data":{"label":"Output","outputType":"video"},"type":"outputNode","position":{"x":750,"y":270}},{"id":"3e039fe9-d53b-4cb4-9bc8-7117aa74d96f","data":{"label":"Text Input","nodeName":"Mood / style","textValue":"","fieldLabel":"Mood / style","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":-195,"y":360}},{"id":"18121f26-e0ac-4ffa-9e5d-b489e218f5d8","data":{"label":"Text Input","nodeName":"Dish name","textValue":"","fieldLabel":"Dish name","placeholder":"Enter text value..."},"type":"textInputNode","position":{"x":-195,"y":135}}]},"example_inputs":[],"preview_images":["https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-350094bc-292c-4074-8fad-86322727de7e-1775811130658-0.jpg?t=1775811131412","https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-350094bc-292c-4074-8fad-86322727de7e-1775887462703-0.jpg?t=1775887464836","https://mlbzgtoiozqztoszvkuc.supabase.co/storage/v1/object/public/preset-thumbnails/fb4de7e2-9f6e-459b-bb1b-464f6ae14bea/flow-preview-350094bc-292c-4074-8fad-86322727de7e-1775887464836-1.jpg?t=1775887465819"],"setup_instructions":"อัปโหลดภาพอาหารเสียบไม้ที่ต้องการ 1 ภาพ โดยควรเป็นภาพที่เห็นตัวอาหารชัดเจน ไม่ถูกบังมากเกินไป และมีรายละเอียดของเมนูพอสมควร ระบบจะนำภาพต้นฉบับไปปรับให้เป็นภาพสไตล์ Hero Shot แบบมืออาชีพ ช่วยให้อาหารดูน่ารับประทานมากขึ้น เหมาะสำหรับใช้บนเมนู ป้ายโปรโมต หรือคอนเทนต์การตลาด หากต้องการผลลัพธ์ที่ตรงขึ้น สามารถระบุอารมณ์ภาพเพิ่มเติมได้ เช่น ร้อน ๆ ย่างหอม ๆ พรีเมียม สตรีทฟู้ด หรือโทนร้านอาหารญี่ปุ่น"},"base_cost":300,"embedding":"[0.0056553422,0.00838753,0.014521567,-0.094604276,-0.020847037,0.0066075274,0.0003124148,0.020957993,-