8057-9f40-429f-8df8-ed6ef8c24baeref_image","source":"327c06dd-a1fc-474f-83f3-2ca9c6d875a0","target":"99b28057-9f40-429f-8df8-ed6ef8c24bae","sourceHandle":"default","targetHandle":"ref_image"},{"id":"xy-edge__0877a865-56e5-40ee-a23e-975db9b5f6dadefault-99b28057-9f40-429f-8df8-ed6ef8c24baeref_image","source":"0877a865-56e5-40ee-a23e-975db9b5f6da","target":"99b28057-9f40-429f-8df8-ed6ef8c24bae","sourceHandle":"default","targetHandle":"ref_image"},{"id":"xy-edge__99b28057-9f40-429f-8df8-ed6ef8c24baeimage-bcd7d795-eaf7-4876-9bf6-f575bd200d4bdefault","source":"99b28057-9f40-429f-8df8-ed6ef8c24bae","target":"bcd7d795-eaf7-4876-9bf6-f575bd200d4b","sourceHandle":"image","targetHandle":"default"}],"nodes":[{"id":"99b28057-9f40-429f-8df8-ed6ef8c24bae","data":{"label":"Banana Pro (Image Gen)","params":{"prompt":"โฟร์กราวด์เป็นมือคนยื่นแก้วเครื่องดื่ม ตามภาพ @@[แก้วเครื่องดื่ม](327c06dd-a1fc-474f-83f3-2ca9c6d875a0) จัดท่าจับและมุมยื่นแก้วให้เหมือนภาพตัวอย่าง @@[Creator Image](9671bce2-d9d9-439d-bcbf-57ef93158e99)  คือมืออยู่กึ่งกลางค่อนไปทางขวา แก้วเอียงเล็กน้อยเข้าหากล้อง ระยะใกล้แบบครอปให้เห็นมือและแก้วเด่นชัด รายละเอียดผิวมือและหยดน้ำเกาะแก้วคมชัด\n\n\n\nแบคกราวด์เป็นคาเฟ่ตามภาพ @@[คาเฟ่](0877a865-56e5-40ee-a23e-975db9b5f6da)  จัดองค์ประกอบให้มีทางเดิน/พื้นที่ว่างนำสายตาไปด้านหลัง แต่ทั้งหมดต้องละลายฉากหลังเป็นโบเก้และเบลอชัดเจน เพื่อให้โฟกัสอยู่ที่ “มือและแก้ว” เท่านั้น\n\n\n\nโทนแสงรวมเป็นแสงธรรมชาติอุ่นนุ่มจากด้านข้าง/ด้านหลังเล็กน้อย ให้ไฮไลต์สะท้อนบนฝาและผิวแก้ว เงามืออ่อน ไม่แข็งกระด้าง คอนทราสต์พอดี สีผิวเป็นธรรมชาติ ฉากหลังมืดลงเล็กน้อยเพื่อดันตัวแบบให้เด่น ใช้ระยะชัดตื้นมาก (shallow depth of field) ให้ฉากหลังเบลอหนัก แต่ขอบแก้ว โลโก้/ตัวอักษรบนแก้ว (ถ้ามี) และนิ้วมือคมชัดที่สุด ภาพรวมให้ความรู้สึกเหมือนถ่ายด้วยเลนส์ 50mm f/1.8 โฟกัสที่แก้วและมือ พร้อมเกรนเล็กน้อยแบบภาพถ่ายจริง.","model_name":"nano-banana-2","aspect_ratio":"Auto"},"exposed":{}},"type":"bananaProNode","position":{"x":298.17626848979035,"y":190.60271958628067}},{"id":"327c06dd-a1fc-474f-83f3-2ca9c6d875a