sourceHandle":"image","targetHandle":"default"}],"nodes":[{"id":"a296bbbc-b6ff-470d-959f-733b4556779a","data":{"label":"Banana Pro (Image Gen)","params":{"prompt":"พรอมสำหรับสร้างภาพแฟชั่นเครื่องประดับลักชัวรีสมจริง (ปรับโมเดล/เครื่องประดับได้): ใช้รูปร่างและใบหน้าของนางแบบจาก {model_reference}@@[นางแบบ](6a1f218d-c8f0-47bd-a70b-27fc3403e89a)  คงเอกลักษณ์ใบหน้า ทรงผม และสีผิว แต่เปลี่ยนชุดเป็นโทนขาว/ครีมเรียบหรู (เช่น sleeveless blazer top หรือเดรสคัตติ้งเนี้ยบ) ให้ตัวแบบเอนแขนพาดบนแท่น/บล็อกสีอ่อน มือวางซ้อนอย่างเป็นธรรมชาติ ใบหน้าก้มเล็กน้อย สีหน้าอ่อนโยน นิ่งสงบ; สวมชุดเครื่องประดับทั้งหมดจาก {jewelry_reference}@@[เซ็ตเครื่องประดับ](db24229a-386e-4906-b427-ac1239b0bc73)  ให้ตรงแบบ ทั้งประเภทและจำนวนชิ้นต้องตรงกับภาพอ้างอิง: ต่างหู (คู่), จี้สร้อยคอ, แหวน และกำไล/สร้อยข้อมือ ตามตำแหน่งจริง ปรับขนาดเครื่องประดับให้สมจริง ไม่ใหญ่หรือเล็กเกินไป รายละเอียดหนามเตยและเพชรเม็ดเล็กคมชัด โฟกัสที่มือและเครื่องประดับเป็นหลัก มุมแคบโคลสอัพตามต้นแบบ ให้เห็นพื้นผิวโลหะและเม็ดเพชรอย่างชัดเจน ไฮไลต์บนอัญมณีเป็นสเปคคูลาร์คม รายละเอียดผิวมนุษย์จริงมีรูขุมขนและผิวสัมผัสธรรมชาติ ไม่เนียนพลาสติก ไม่ CGI/วาด/อนิเมะ ความละเอียดสูงระดับงานโฆษณาเครื่องประดับ; ฉากหลังสตูดิโอเรียบ โทนอ่อน มีเท็กซ์เจอร์ปูน/หินอ่อนจางๆ แบบมินิมอล; แสงสตูดิโอแบบ beauty lighting เหมือนกลางแจ้ง: soft key light ด้านหน้าเฉียง, fill เบาๆ ลดเงาแข็ง, rim light บางๆ ให้ขอบผมและเครื่องประดับมีประกาย; เลนส์พอร์ตเทรตประมาณ 85mm, f/2.0 ให้ชัดลึกตื้น โทนภาพหรูหรา คอนทราสต์พอดี ให้พรอมเป็นพรอมกลางสามารถเปลี่ยนโมเดลและชุดเครื่องประดับได้โดยแทนที่ {model_reference}@@[นางแบบ](6a1f218d-c8f0-47bd-a70b-27fc3403e89a)  และ {jewelry_reference}@@[เซ็ตเครื่องประดับ](db24229a-386e-4906-b427-ac1239b0bc73) ","model_name":"nano-banana-pro","aspect_ratio":"3:4"},"exposed":{}},"type":"bananaProNode","position":{"x":270,"y":345}},{"id":"db24229a-386e-4906-b427-ac1239b0bc73","data":{"label":"Image Upload","accept":"image/*","nodeName":"เซ็ตเครื่องประดับ","required":true,"fieldType":"image","fieldLabel":"เซ็ตเครื่องประดับ"},"type":"inputNode","